<template>
    <div class="m-news bg-white p-5 shadow-xs border border-gray-200 border-opacity-60 mb-6">
        <div class="m-news-header">
            <div class="u-left">
                <a
                    :href="more_link"
                    class="text-xs flex items-center text-gray-800 uppercase tracking-widest m-0"
                    target="_blank"
                    rel="noopener noreferrer"
                >
                    <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true" v-bind:svg-inline="''" v-bind:class="'w-4 h-4 mr-2 text-indigo-500'" v-bind:role="'presentation'" v-bind:focusable="'false'" v-bind:tabindex="'-1'"><path d="M15 18h-5M18 14h-8M4 22h16a2 2 0 002-2V4a2 2 0 00-2-2H8a2 2 0 00-2 2v16a2 2 0 01-4 0v-9a2 2 0 012-2h2"/><rect width="8" height="4" x="10" y="6" rx="1"/></svg>
                    {{ $t("index.news.title") }}
                </a>
            </div>
            <div
                class="u-right flex bg-gray-100 p-1 rounded-md w-max"
                role="tablist"
                :aria-label="$t('index.news.categoryAria')"
            >
                <button
                    v-for="item in modeList"
                    :key="item.value"
                    class="u-btn px-2 py-1 text-[12px] rounded transition-all border-0 bg-transparent cursor-pointer tracking-wider"
                    :class="
                        item.value === mode ? 'bg-white text-indigo-600 shadow-sm' : 'text-gray-500 hover:text-gray-700'
                    "
                    :aria-pressed="item.value === mode"
                    @click="switchMode(item.value)"
                >
                    {{ item.label }}
                </button>
            </div>
        </div>
        <ul class="m-news-list m-sideblock-list" v-if="data">
            <li v-for="(item, i) in data" :key="i">
                <em v-if="item.time" class="u-time font-sans tabular-nums">{{ dateFormat(item.time) }}</em>
                <a
                    class="u-title"
                    :href="item.url"
                    target="_blank"
                    rel="noopener noreferrer"
                    :style="itemStyle(item)"
                    >{{ item.title }}</a
                >
            </li>
        </ul>
    </div>
</template>

<script>
import { getPostsFree } from "@/service/index";
import dateFormat from "@/utils/dateFormat.js";
import { getChangelog, getGameNews } from "@/service/cms";
import { getLink } from "@jx3box/jx3box-common/js/utils";
import JX3_ZLP from "@jx3box/jx3box-common/data/jx3_zlp.json";
import dayjs from "dayjs";

const { all_map } = JX3_ZLP;
export default {
    name: "IndexNews",
    components: {},
    data: function () {
        return {
            mode: "all",

            // 游戏
            all_links: {
                std: "https://jx3.xoyo.com/allnews/",
                origin: "https://jx3yq.xoyo.com/index/#/latest",
            },
            game_links: {
                std: "https://jx3.xoyo.com/allnews/",
                origin: "https://jx3yq.xoyo.com/index/#/latest",
            },
            skill_change_links: {
                std: "/pvp/changelog",
                origin: "/pvp/changelog",
            },
            game_data: [],

            // 魔盒
            box_links: {
                std: "/notice",
                origin: "/notice",
            },
            box_data: [],

            // 技改
            skill_change_data: [],
        };
    },
    computed: {
        client: function () {
            return this.$store.state.client;
        },
        modeList: function () {
            return [
                { label: this.$t("index.news.tabs.all"), value: "all" },
                { label: this.$t("index.news.tabs.game"), value: "game" },
                { label: this.$t("index.news.tabs.skillChange"), value: "skill_change" },
                { label: this.$t("index.news.tabs.box"), value: "box" },
            ];
        },
        more_link: function () {
            return this[this.mode + "_links"]?.[this.client] || "/";
        },
        all_data: function () {
            let list = [...this.game_data.slice(0, 3), ...this.box_data.slice(0, 2)];
            // list = list.sort((a, b) => {
            //     return b.time - a.time;
            // });
            return list.slice(0, 5);
        },
        data: function () {
            return this.mode == "all" ? this.all_data : this[this.mode + "_data"];
        },
        zlp_map() {
            // 生成对象 {key: value}
            return all_map.reduce((obj, item) => {
                obj[item.value] = item.label;
                return obj;
            }, {});
        },
    },
    methods: {
        dateFormat: function (val) {
            return dateFormat(val, "-");
        },
        linkFormat: function (val) {
            if (val.startsWith("/")) {
                return "https://jx3.xoyo.com" + val;
            } else {
                return val;
            }
        },
        switchMode: function (val) {
            this.mode = val;
        },
        loadGameData: function () {
            getGameNews({ client: this.client }).then((res) => {
                this.game_data = res?.data.data.list
                    .map((item) => {
                        item.time = dayjs(item.post_date).toDate();
                        item.type = "game";
                        item.title = item.post_title;
                        item.url = item.post_url;
                        return item;
                    })
                    .slice(0, 5);
            });
        },
        loadBoxData: function () {
            getPostsFree({
                client: this.client,
                type: "notice",
                per: 5,
                sticky: 1,
            }).then((res) => {
                this.box_data = res.data.data?.list?.map((item) => {
                    item.title = item.post_title;
                    item.url = `/notice/${item.ID}`;
                    item.time = new Date(item.post_modified);
                    item.type = "box";
                    return item;
                });
            });
        },
        loadSkillChangeData: function () {
            const params = {
                client: this.client,
            };
            getChangelog(params).then((res) => {
                this.skill_change_data = (res.data.data?.list || []).slice(0, 5).map((item) => {
                    item.title = `【${this.zlp_map[item.zlp]}】${item.title}`;
                    item.url = item.link || getLink("bps", item.post_id);
                    item.time = new Date(item.date);
                    item.type = "skill_change";
                    return item;
                });
            });
        },
        itemStyle(item) {
            if (item?.color) {
                return {
                    color: item.color,
                    fontWeight: "bold",
                };
            }
            return {};
        },
    },
    mounted: function () {
        this.loadGameData();
        this.loadBoxData();
        this.loadSkillChangeData();
    },
};
</script>

